import React, { useState, useEffect } from 'react';
import { supabase } from '../lib/supabaseClient';
import { Admin, HumanResource } from '../types';
import { 
    Shield, Users, Server, Activity, Plus, Trash2, 
    CheckCircle, XCircle, Database, AlertCircle, 
    Briefcase, Save, X, Loader2, Wifi 
} from 'lucide-react';

const SystemAdminPage: React.FC = () => {
    const [admins, setAdmins] = useState<Admin[]>([]);
    const [hrs, setHrs] = useState<HumanResource[]>([]);
    const [loading, setLoading] = useState(true);

    // System Health State
    const [dbStatus, setDbStatus] = useState<'Connected' | 'Disconnected' | 'Checking'>('Checking');
    const [latency, setLatency] = useState<number>(0);
    const [totalUsers, setTotalUsers] = useState<number>(0);

    // Modal States
    const [showAddAdmin, setShowAddAdmin] = useState(false);
    const [showAddHR, setShowAddHR] = useState(false);
    const [processing, setProcessing] = useState(false);

    // Forms
    const [newAdmin, setNewAdmin] = useState({ username: '', password: '' });
    const [newHR, setNewHR] = useState({ company_name: '', username: '', password: '' });

    useEffect(() => {
        fetchSystemData();
        checkSystemHealth();

        // Poll health every 30 seconds
        const interval = setInterval(checkSystemHealth, 30000);
        return () => clearInterval(interval);
    }, []);

    const checkSystemHealth = async () => {
        const start = performance.now();
        try {
            const { count, error } = await supabase.from('admins').select('*', { count: 'exact', head: true });
            const end = performance.now();

            if (error) throw error;

            setLatency(Math.round(end - start));
            setDbStatus('Connected');
        } catch (e) {
            setDbStatus('Disconnected');
            setLatency(0);
        }
    };

    const fetchSystemData = async () => {
        setLoading(true);
        try {
            const [adminRes, hrRes, studentCount, alumniCount] = await Promise.all([
                supabase.from('admins').select('*'),
                supabase.from('human_resource').select('*'),
                supabase.from('students').select('*', { count: 'exact', head: true }),
                supabase.from('alumni').select('*', { count: 'exact', head: true })
            ]);

            if (adminRes.data) setAdmins(adminRes.data);
            if (hrRes.data) setHrs(hrRes.data);
            setTotalUsers((studentCount.count || 0) + (alumniCount.count || 0));

        } catch (e) {
            console.error("Fetch error", e);
        } finally {
            setLoading(false);
        }
    };

    const handleAddAdmin = async (e: React.FormEvent) => {
        e.preventDefault();
        setProcessing(true);
        try {
            const { data, error } = await supabase.from('admins').insert([newAdmin]).select().single();
            if (error) throw error;
            setAdmins([...admins, data]);
            setShowAddAdmin(false);
            setNewAdmin({ username: '', password: '' });
            alert("Administrator added successfully.");
        } catch (e: any) {
            alert("Error adding admin: " + e.message);
        } finally {
            setProcessing(false);
        }
    };

    const handleDeleteAdmin = async (id: string) => {
        if (!window.confirm("Are you sure? This will revoke access immediately.")) return;
        try {
            await supabase.from('admins').delete().eq('id', id);
            setAdmins(prev => prev.filter(a => a.id !== id));
        } catch (e) {
            alert("Failed to delete admin.");
        }
    };

    const handleAddHR = async (e: React.FormEvent) => {
        e.preventDefault();
        setProcessing(true);
        try {
            const { data, error } = await supabase.from('human_resource').insert([newHR]).select().single();
            if (error) throw error;
            setHrs([...hrs, data]);
            setShowAddHR(false);
            setNewHR({ company_name: '', username: '', password: '' });
            alert("HR Account created successfully.");
        } catch (e: any) {
            alert("Error adding HR: " + e.message);
        } finally {
            setProcessing(false);
        }
    };

    const handleDeleteHR = async (id: number) => {
        if (!window.confirm("Are you sure? This will remove the HR account and close their job postings.")) return;
        try {
            await supabase.from('human_resource').delete().eq('id', id);
            setHrs(prev => prev.filter(h => h.id !== id));
        } catch (e) {
            alert("Failed to delete HR account.");
        }
    };

    const StatusCard = ({ icon: Icon, label, value, subtext, color }: any) => (
        <div className={`p-6 rounded-3xl border border-white/50 shadow-lg backdrop-blur-xl bg-gradient-to-br ${color} text-white relative overflow-hidden group`}>
            <div className="absolute top-0 right-0 w-24 h-24 bg-white/10 rounded-full blur-2xl -translate-y-1/2 translate-x-1/2 group-hover:bg-white/20 transition-all"></div>
            <div className="relative z-10 flex justify-between items-start">
                <div>
                    <div className="flex items-center gap-2 mb-2 opacity-90">
                        <Icon size={18} />
                        <span className="text-xs font-bold uppercase tracking-wider">{label}</span>
                    </div>
                    <h3 className="text-3xl font-black">{value}</h3>
                    <p className="text-xs font-medium mt-1 opacity-80">{subtext}</p>
                </div>
                <div className="p-3 bg-white/20 rounded-2xl backdrop-blur-md">
                    <Activity size={24} className="animate-pulse" />
                </div>
            </div>
        </div>
    );

    return (
        <div className="space-y-8 animate-fade-in pb-10">

            {/* Header */}
            <div className="flex items-center justify-between bg-white/40 backdrop-blur-xl p-6 rounded-3xl border border-white/50 shadow-lg shadow-indigo-500/5">
                <div>
                    <h2 className="text-2xl font-bold text-slate-800 flex items-center gap-3">
                        <Shield className="text-indigo-600" /> System Control Panel
                    </h2>
                    <p className="text-slate-500 mt-1">Monitor infrastructure and manage privileged accounts.</p>
                </div>
                <div className="flex items-center gap-2 px-4 py-2 bg-emerald-50 text-emerald-700 rounded-full border border-emerald-200 text-xs font-bold shadow-sm">
                    <div className="w-2 h-2 rounded-full bg-emerald-500 animate-ping"></div>
                    System Online
                </div>
            </div>

            {/* Status Cards */}
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
                <StatusCard 
                    icon={Wifi} 
                    label="System Status" 
                    value="Online" 
                    subtext="All services operational" 
                    color="from-emerald-500 to-teal-600"
                />
                <StatusCard 
                    icon={Database} 
                    label="Database" 
                    value={dbStatus} 
                    subtext={dbStatus === 'Connected' ? `${latency}ms latency` : "Connection Failed"} 
                    color={dbStatus === 'Connected' ? "from-blue-500 to-indigo-600" : "from-red-500 to-rose-600"}
                />
                <StatusCard 
                    icon={Users} 
                    label="Total Users" 
                    value={totalUsers} 
                    subtext="Alumni & Students" 
                    color="from-violet-500 to-purple-600"
                />
                <StatusCard 
                    icon={Shield} 
                    label="Active Admins" 
                    value={admins.length} 
                    subtext="Privileged Access" 
                    color="from-orange-500 to-amber-600"
                />
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">

                {/* Admin Management */}
                <div className="bg-white/60 backdrop-blur-xl border border-white/50 shadow-lg shadow-slate-200/50 rounded-3xl p-6 flex flex-col h-[500px]">
                    <div className="flex justify-between items-center mb-6">
                        <h3 className="font-bold text-slate-800 flex items-center gap-2">
                            <Shield className="text-orange-500" size={20}/> Administrator Accounts
                        </h3>
                        <button 
                            onClick={() => setShowAddAdmin(true)}
                            className="px-4 py-2 bg-slate-900 text-white text-xs font-bold rounded-xl flex items-center gap-2 hover:bg-black transition-all shadow-md"
                        >
                            <Plus size={14}/> Add Admin
                        </button>
                    </div>

                    <div className="flex-grow overflow-y-auto custom-scrollbar space-y-3 pr-2">
                        {loading ? <div className="text-center py-10"><Loader2 className="animate-spin mx-auto text-slate-300"/></div> : 
                         admins.map(admin => (
                            <div key={admin.id} className="p-4 bg-white rounded-2xl border border-slate-100 flex justify-between items-center shadow-sm hover:shadow-md transition-all group">
                                <div className="flex items-center gap-3">
                                    <div className="w-10 h-10 bg-orange-50 text-orange-600 rounded-xl flex items-center justify-center font-bold">
                                        {admin.username.charAt(0).toUpperCase()}
                                    </div>
                                    <div>
                                        <h4 className="font-bold text-slate-800 text-sm">{admin.username}</h4>
                                        <span className="text-[10px] font-bold bg-orange-100 text-orange-700 px-2 py-0.5 rounded border border-orange-200">Super Admin</span>
                                    </div>
                                </div>
                                <button onClick={() => handleDeleteAdmin(admin.id)} className="p-2 text-slate-300 hover:text-red-500 hover:bg-red-50 rounded-lg transition-colors">
                                    <Trash2 size={18} />
                                </button>
                            </div>
                        ))}
                    </div>
                </div>

                {/* HR Management */}
                <div className="bg-white/60 backdrop-blur-xl border border-white/50 shadow-lg shadow-slate-200/50 rounded-3xl p-6 flex flex-col h-[500px]">
                    <div className="flex justify-between items-center mb-6">
                        <h3 className="font-bold text-slate-800 flex items-center gap-2">
                            <Briefcase className="text-blue-500" size={20}/> Human Resource Accounts
                        </h3>
                        <button 
                            onClick={() => setShowAddHR(true)}
                            className="px-4 py-2 bg-blue-600 text-white text-xs font-bold rounded-xl flex items-center gap-2 hover:bg-blue-700 transition-all shadow-md"
                        >
                            <Plus size={14}/> Add HR
                        </button>
                    </div>

                    <div className="flex-grow overflow-y-auto custom-scrollbar space-y-3 pr-2">
                        {loading ? <div className="text-center py-10"><Loader2 className="animate-spin mx-auto text-slate-300"/></div> : 
                         hrs.length === 0 ? <div className="text-center py-10 text-slate-400 text-sm">No HR accounts found.</div> :
                         hrs.map(hr => (
                            <div key={hr.id} className="p-4 bg-white rounded-2xl border border-slate-100 flex justify-between items-center shadow-sm hover:shadow-md transition-all group">
                                <div className="flex items-center gap-3">
                                    <div className="w-10 h-10 bg-blue-50 text-blue-600 rounded-xl flex items-center justify-center font-bold">
                                        {hr.company_name.charAt(0).toUpperCase()}
                                    </div>
                                    <div>
                                        <h4 className="font-bold text-slate-800 text-sm">{hr.company_name}</h4>
                                        <p className="text-xs text-slate-500 flex items-center gap-1"><Users size={10}/> @{hr.username}</p>
                                    </div>
                                </div>
                                <button onClick={() => handleDeleteHR(hr.id)} className="p-2 text-slate-300 hover:text-red-500 hover:bg-red-50 rounded-lg transition-colors">
                                    <Trash2 size={18} />
                                </button>
                            </div>
                        ))}
                    </div>
                </div>
            </div>

            {/* Modals */}
            {showAddAdmin && (
                <div className="fixed inset-0 z-50 flex items-center justify-center p-4">
                    <div className="absolute inset-0 bg-slate-900/40 backdrop-blur-sm" onClick={() => setShowAddAdmin(false)}></div>
                    <div className="bg-white rounded-2xl shadow-xl w-full max-w-sm relative z-10 p-6 animate-in zoom-in-95">
                        <div className="flex justify-between items-center mb-6">
                            <h3 className="text-lg font-bold text-slate-800">Add Administrator</h3>
                            <button onClick={() => setShowAddAdmin(false)}><X size={20} className="text-slate-400"/></button>
                        </div>
                        <form onSubmit={handleAddAdmin} className="space-y-4">
                            <div>
                                <label className="text-xs font-bold text-slate-500 uppercase mb-1 block">Username</label>
                                <input type="text" required value={newAdmin.username} onChange={e => setNewAdmin({...newAdmin, username: e.target.value})} className="w-full px-4 py-2 bg-slate-50 border border-slate-200 rounded-xl outline-none focus:border-orange-500 transition-colors"/>
                            </div>
                            <div>
                                <label className="text-xs font-bold text-slate-500 uppercase mb-1 block">Password</label>
                                <input type="password" required value={newAdmin.password} onChange={e => setNewAdmin({...newAdmin, password: e.target.value})} className="w-full px-4 py-2 bg-slate-50 border border-slate-200 rounded-xl outline-none focus:border-orange-500 transition-colors"/>
                            </div>
                            <button type="submit" disabled={processing} className="w-full py-3 bg-slate-900 text-white font-bold rounded-xl hover:bg-black transition-all flex justify-center">
                                {processing ? <Loader2 className="animate-spin"/> : "Create Account"}
                            </button>
                        </form>
                    </div>
                </div>
            )}

            {showAddHR && (
                <div className="fixed inset-0 z-50 flex items-center justify-center p-4">
                    <div className="absolute inset-0 bg-slate-900/40 backdrop-blur-sm" onClick={() => setShowAddHR(false)}></div>
                    <div className="bg-white rounded-2xl shadow-xl w-full max-w-sm relative z-10 p-6 animate-in zoom-in-95">
                        <div className="flex justify-between items-center mb-6">
                            <h3 className="text-lg font-bold text-slate-800">Add HR Partner</h3>
                            <button onClick={() => setShowAddHR(false)}><X size={20} className="text-slate-400"/></button>
                        </div>
                        <form onSubmit={handleAddHR} className="space-y-4">
                            <div>
                                <label className="text-xs font-bold text-slate-500 uppercase mb-1 block">Company Name</label>
                                <input type="text" required value={newHR.company_name} onChange={e => setNewHR({...newHR, company_name: e.target.value})} className="w-full px-4 py-2 bg-slate-50 border border-slate-200 rounded-xl outline-none focus:border-blue-500 transition-colors"/>
                            </div>
                            <div>
                                <label className="text-xs font-bold text-slate-500 uppercase mb-1 block">Username</label>
                                <input type="text" required value={newHR.username} onChange={e => setNewHR({...newHR, username: e.target.value})} className="w-full px-4 py-2 bg-slate-50 border border-slate-200 rounded-xl outline-none focus:border-blue-500 transition-colors"/>
                            </div>
                            <div>
                                <label className="text-xs font-bold text-slate-500 uppercase mb-1 block">Password</label>
                                <input type="password" required value={newHR.password} onChange={e => setNewHR({...newHR, password: e.target.value})} className="w-full px-4 py-2 bg-slate-50 border border-slate-200 rounded-xl outline-none focus:border-blue-500 transition-colors"/>
                            </div>
                            <button type="submit" disabled={processing} className="w-full py-3 bg-blue-600 text-white font-bold rounded-xl hover:bg-blue-700 transition-all flex justify-center">
                                {processing ? <Loader2 className="animate-spin"/> : "Create HR Account"}
                            </button>
                        </form>
                    </div>
                </div>
            )}

        </div>
    );
};

export default SystemAdminPage;

import React, { useState } from 'react';
import { LogOut, Users, Database, LayoutDashboard, ChevronRight, Menu, Bell, Search, Settings, CheckCircle, FileText, Globe, Inbox, Bot, AlertTriangle, GraduationCap, Shield } from 'lucide-react';
import HomePage from './HomePage';
import UserManagement from './UserManagement';
import ApprovalWorkflow from './ApprovalWorkflow';
import ReportsPage from './ReportsPage';
import AlumniFetcherPage from './AlumniFetcherPage';
import InboxPage from './InboxPage';
import PauloPage from './PauloPage';
import SystemAdminPage from './SystemAdminPage';
import { Admin } from '../types';

interface AdminDashboardProps {
  admin: Admin;
  onLogout: () => void;
}

const AdminDashboard: React.FC<AdminDashboardProps> = ({ admin, onLogout }) => {
  const [currentTab, setCurrentTab] = useState<'dashboard' | 'users' | 'approvals' | 'reports' | 'fetcher' | 'inbox' | 'paulo' | 'settings' | 'system'>('dashboard');
  const [showLogoutModal, setShowLogoutModal] = useState(false);

  const handleLogoutClick = () => {
    setShowLogoutModal(true);
  };

  const confirmLogout = () => {
    setShowLogoutModal(false);
    onLogout();
  };

  const NavItem = ({ id, label, icon: Icon }: { id: typeof currentTab, label: string, icon: any }) => (
    <button 
        onClick={() => setCurrentTab(id)}
        className={`w-full flex items-center justify-between px-4 py-3 rounded-xl transition-all duration-200 text-sm font-bold group relative overflow-hidden mb-1 ${
            currentTab === id 
            ? 'bg-gradient-to-r from-blue-600 to-indigo-600 text-white shadow-md shadow-blue-500/20' 
            : 'text-slate-600 hover:bg-white/50 hover:text-blue-600'
        }`}
    >
        <div className="flex items-center gap-3 relative z-10">
            <Icon size={18} className={currentTab === id ? 'text-white' : 'text-slate-400 group-hover:text-blue-500'} />
            <span>{label}</span>
        </div>
        {currentTab === id && <ChevronRight size={16} className="relative z-10 opacity-80" />}
    </button>
  );

  return (
    <div className="h-screen w-screen relative flex flex-col font-sans text-slate-800 overflow-hidden bg-slate-50">

      {/* --- Glassmorphism Background Blobs --- */}
      <div className="fixed inset-0 z-0 pointer-events-none overflow-hidden">
          <div className="absolute top-[-10%] left-[-10%] w-[50%] h-[50%] rounded-full bg-blue-400/30 blur-[120px] animate-blob"></div>
          <div className="absolute bottom-[-10%] right-[-10%] w-[50%] h-[50%] rounded-full bg-purple-400/30 blur-[120px] animate-blob animation-delay-2000"></div>
          <div className="absolute top-[40%] left-[40%] w-[30%] h-[30%] rounded-full bg-indigo-300/20 blur-[100px] animate-blob animation-delay-4000"></div>
      </div>

      {/* Top Bar - Glass Style - Fixed at Top */}
      <header className="flex-none z-50 mx-4 lg:mx-8 mt-4 rounded-2xl bg-white/60 backdrop-blur-xl border border-white/80 shadow-lg shadow-black/5 relative">
        <div className="px-6 h-20 flex justify-between items-center">

             {/* Left: Brand */}
             <div className="flex items-center gap-4">
                 <div className="w-10 h-10 bg-blue-600 rounded-xl flex items-center justify-center shadow-lg shadow-blue-600/20 text-white">
                     <GraduationCap className="w-6 h-6" />
                 </div>
                 <div>
                    <h1 className="text-xl font-bold text-slate-800 tracking-tight">Admin<span className="text-blue-600">Portal</span></h1>
                    <p className="text-[10px] font-bold tracking-widest uppercase">
                        <span className="text-slate-900">Laguna</span> <span className="text-green-600">University</span>
                    </p>
                 </div>
             </div>

             {/* Right: Actions */}
             <div className="flex items-center gap-4 md:gap-6">

                {/* Search Bar - High Visibility */}
                <div className="hidden md:flex items-center bg-white rounded-xl px-4 py-2 border border-slate-200 shadow-sm focus-within:shadow-md focus-within:border-blue-300 transition-all w-64 group">
                    <Search size={16} className="text-slate-400 group-focus-within:text-blue-500 mr-2 transition-colors" />
                    <input type="text" placeholder="Quick Search..." className="bg-transparent border-none outline-none text-sm text-slate-700 w-full placeholder-slate-400 font-medium"/>
                </div>

                <div className="h-8 w-[1px] bg-slate-200 hidden md:block"></div>

                <div className="flex items-center gap-3">
                    <button className="p-2.5 rounded-xl bg-white/70 border border-white/80 hover:bg-white hover:shadow-md text-slate-600 transition-all">
                        <Bell size={20} />
                    </button>
                    <button onClick={() => setCurrentTab('settings')} className="p-2.5 rounded-xl bg-white/70 border border-white/80 hover:bg-white hover:shadow-md text-slate-600 transition-all">
                        <Settings size={20} />
                    </button>
                </div>

                {/* Profile / Logout */}
                <div className="flex items-center gap-3 pl-2">
                    <div className="hidden sm:flex items-center gap-2 px-4 py-2 bg-white/50 border border-white/60 rounded-full shadow-sm">
                        <span className="text-xs font-bold text-slate-700">{admin.username}</span>
                        <span className="h-3 w-px bg-slate-300"></span>
                        <span className="text-[10px] font-bold text-blue-600 uppercase tracking-wider">Administrator</span>
                    </div>
                    <button 
                        onClick={handleLogoutClick}
                        className="ml-2 p-2.5 rounded-xl bg-white/70 border border-white/80 text-red-500 hover:bg-red-50 hover:text-red-600 transition-all shadow-sm"
                        title="Sign Out"
                    >
                        <LogOut size={18} />
                    </button>
                </div>
            </div>
        </div>
      </header>

      {/* Main Layout - Content Scrollable Only */}
      <div className="flex-grow flex overflow-hidden pt-6 pb-6 px-4 lg:px-8 relative z-[60] gap-8">

            {/* === LEFT SIDEBAR NAVIGATION (Fixed Width) === */}
            <div className="hidden lg:flex flex-col w-72 flex-shrink-0">
                 <div className="bg-white/60 backdrop-blur-xl border border-white/60 shadow-xl shadow-indigo-500/5 rounded-3xl p-4 h-full overflow-y-auto custom-scrollbar">

                    {/* Section: Dashboard */}
                    <div className="mb-6">
                        <div className="px-4 py-2 mb-1">
                            <h3 className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Dashboard</h3>
                        </div>
                        <NavItem id="dashboard" label="Overview" icon={LayoutDashboard} />
                    </div>

                    {/* Section: AI & Communication */}
                    <div className="mb-6">
                        <div className="px-4 py-2 mb-1">
                            <h3 className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">AI & Communication</h3>
                        </div>
                        <NavItem id="inbox" label="Updates Inbox" icon={Inbox} />
                        <NavItem id="paulo" label="P.A.U.L.O. Assistant" icon={Bot} />
                    </div>

                    {/* Section: User & Records Management */}
                    <div className="mb-6">
                        <div className="px-4 py-2 mb-1">
                            <h3 className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">User & Records</h3>
                        </div>
                        <NavItem id="users" label="User Database" icon={Users} />
                        <NavItem id="approvals" label="Approvals" icon={CheckCircle} />
                    </div>

                    {/* Section: Alumni & Placement Tools */}
                    <div className="mb-6">
                        <div className="px-4 py-2 mb-1">
                            <h3 className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Placement Tools</h3>
                        </div>
                        <NavItem id="fetcher" label="Alumni Fetcher" icon={Globe} />
                        <NavItem id="reports" label="Generate Reports" icon={FileText} />
                    </div>

                    {/* Section: System */}
                    <div className="mb-6">
                        <div className="px-4 py-2 mb-1">
                            <h3 className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">System</h3>
                        </div>
                        <NavItem id="system" label="System Panel" icon={Shield} />
                        <NavItem id="settings" label="Settings" icon={Settings} />

                        <button 
                            onClick={handleLogoutClick}
                            className="w-full flex items-center gap-3 px-4 py-3 mt-2 rounded-xl transition-all duration-200 text-sm font-bold text-red-500 hover:bg-red-50"
                        >
                            <LogOut size={18} />
                            <span>Log Out</span>
                        </button>
                    </div>

                 </div>
            </div>

            {/* === RIGHT CONTENT AREA (Scrollable) === */}
            <main className="flex-grow h-full overflow-y-auto pr-2 scrollbar-hide">
                {currentTab === 'dashboard' && <HomePage adminId={admin.id} />}
                {currentTab === 'inbox' && <InboxPage />}
                {currentTab === 'paulo' && <PauloPage />}
                {currentTab === 'users' && <UserManagement />}
                {currentTab === 'approvals' && <ApprovalWorkflow onUpdate={() => {}} />}
                {currentTab === 'fetcher' && <AlumniFetcherPage />}
                {currentTab === 'reports' && <ReportsPage adminId={admin.id} />}
                {currentTab === 'system' && <SystemAdminPage />}
                {currentTab === 'settings' && (
                    <div className="flex items-center justify-center h-full text-slate-400">
                        <div className="text-center">
                            <Settings size={48} className="mx-auto mb-4 opacity-50"/>
                            <h2 className="text-xl font-bold text-slate-600">System Settings</h2>
                            <p className="text-sm">Configuration options coming soon.</p>
                        </div>
                    </div>
                )}
            </main>
      </div>

      {/* === LOGOUT CONFIRMATION MODAL === */}
      {showLogoutModal && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4">
            <div className="absolute inset-0 bg-slate-900/40 backdrop-blur-sm animate-in fade-in duration-300" onClick={() => setShowLogoutModal(false)}></div>
            <div className="bg-white rounded-3xl shadow-2xl w-full max-w-sm relative z-10 overflow-hidden animate-in zoom-in-95 duration-300 border border-white/20">
                <div className="p-8 text-center">
                    <div className="w-16 h-16 bg-red-50 rounded-full flex items-center justify-center mx-auto mb-6 shadow-inner">
                        <AlertTriangle className="w-8 h-8 text-red-500" />
                    </div>
                    <h3 className="text-2xl font-black text-slate-800 mb-2">Sign Out?</h3>
                    <p className="text-slate-500 text-sm mb-8 leading-relaxed font-medium">
                        Are you sure you want to log out of the admin portal? Any unsaved changes may be lost.
                    </p>
                    <div className="grid grid-cols-2 gap-3">
                         <button 
                            onClick={() => setShowLogoutModal(false)}
                            className="py-3 bg-slate-100 hover:bg-slate-200 text-slate-600 font-bold rounded-xl transition-colors text-sm"
                        >
                            Cancel
