                        <button 
                            onClick={confirmLogout}
                            className="py-3 bg-red-500 hover:bg-red-600 text-white font-bold rounded-xl shadow-lg shadow-red-200 transition-all text-sm"
                        >
                            Yes, Log Out
                        </button>
