    return (
        <div className="space-y-8 animate-fade-in pb-10">

            {/* Header */}
            <div className="flex items-center justify-between bg-white/40 backdrop-blur-xl p-6 rounded-3xl border border-white/50 shadow-lg shadow-indigo-500/5">
