                                        type="submit"
                                        disabled={loading}
                                        className="w-full bg-gradient-to-r from-luGreen to-luGreen-light text-white font-bold py-3.5 px-4 rounded-xl shadow-lg hover:shadow-xl hover:translate-y-[-1px] active:translate-y-[1px] transition-all duration-300 flex justify-center items-center text-sm tracking-wide mt-2"
                                    >
                                        {loading ? <Loader2 className="animate-spin w-5 h-5 text-white" /> : 'SIGN IN'}
                                    </button>
                                </form>
                            </>
                        ) : (
                            // PORTAL LOGIN FORM (ADMIN / HR)
                            <form onSubmit={handlePortalLogin} className="space-y-5 animate-fade-in">

                                {/* Portal Type Toggle */}
                                <div className="flex bg-gray-100 p-1 rounded-xl mb-4 relative">
                                    <div 
                                    className={`absolute top-1 bottom-1 w-1/2 bg-white rounded-lg shadow-sm transition-all duration-300 ease-in-out ${portalType === 'hr' ? 'translate-x-full' : 'translate-x-0'}`}
                                    ></div>
                                    <button 
                                        type="button"
                                        onClick={() => setPortalType('admin')}
                                        className={`flex-1 relative z-10 py-2 text-xs font-bold uppercase tracking-wide transition-colors ${portalType === 'admin' ? 'text-blue-600' : 'text-gray-500 hover:text-gray-700'}`}
                                    >
                                        Administrator
                                    </button>
                                    <button 
                                        type="button"
                                        onClick={() => setPortalType('hr')}
                                        className={`flex-1 relative z-10 py-2 text-xs font-bold uppercase tracking-wide transition-colors ${portalType === 'hr' ? 'text-blue-600' : 'text-gray-500 hover:text-gray-700'}`}
                                    >
                                        Human Resource
                                    </button>
                                </div>

                                <div className="p-4 bg-blue-50 border border-blue-100 rounded-xl mb-4 flex items-start gap-3">
                                    {portalType === 'admin' ? <ShieldCheck className="text-blue-600 shrink-0 mt-0.5" size={16} /> : <Briefcase className="text-blue-600 shrink-0 mt-0.5" size={16} />}
                                    <p className="text-xs text-blue-800 font-medium">
                                        {portalType === 'admin' 
                                            ? "Access full system database and user management." 
                                            : "Manage job postings and view applicants."}
                                    </p>
                                </div>

                                <div className="group">
                                    <label className="block text-gray-600 text-xs font-bold mb-1.5 ml-1 uppercase tracking-wider">Username</label>
                                    <input 
                                        type="text" 
                                        value={portalUsername}
                                        onChange={(e) => setPortalUsername(e.target.value)}
                                        className="w-full px-4 py-3.5 rounded-xl bg-gray-50 border border-gray-200 focus:border-luGreen focus:bg-white focus:outline-none focus:ring-4 focus:ring-green-500/10 transition-all duration-300 text-gray-800 font-medium"
                                        required
                                    />
                                </div>

                                <div className="group">
                                    <label className="block text-gray-600 text-xs font-bold mb-1.5 ml-1 uppercase tracking-wider">Password</label>
                                    <div className="relative">
                                        <input 
                                            type={showPassword ? "text" : "password"}
                                            value={portalPassword}
                                            onChange={(e) => setPortalPassword(e.target.value)}
                                            className="w-full px-4 py-3.5 rounded-xl bg-gray-50 border border-gray-200 focus:border-luGreen focus:bg-white focus:outline-none focus:ring-4 focus:ring-green-500/10 transition-all duration-300 text-gray-800 font-medium"
                                            required
                                        />
                                        <button
                                            type="button"
                                            onClick={() => setShowPassword(!showPassword)}
                                            className="absolute right-4 top-1/2 transform -translate-y-1/2 text-gray-400 hover:text-luGreen transition-colors focus:outline-none"
                                        >
                                            {showPassword ? <EyeOff size={20} /> : <Eye size={20} />}
                                        </button>
                                    </div>
                                </div>

                                {loginError && (
                                    <div className="p-4 bg-red-50 text-red-800 text-sm rounded-xl flex items-start animate-fade-in border border-red-100 shadow-sm">
                                        <AlertCircle size={18} className="mr-2 mt-0.5 flex-shrink-0 text-red-600" />
                                        <span className="font-medium">{loginError}</span>
                                    </div>
                                )}

                                <button 
                                    type="submit"
                                    disabled={loading}
                                    className="w-full bg-gray-900 text-white font-bold py-3.5 px-4 rounded-xl shadow-lg hover:shadow-xl hover:translate-y-[-1px] active:translate-y-[1px] transition-all duration-300 flex justify-center items-center text-sm tracking-wide mt-2"
                                >
                                    {loading ? <Loader2 className="animate-spin w-5 h-5 text-white" /> : 'SECURE LOGIN'}
                                </button>
                            </form>
                        )}
                    </div>

                    {/* Portal Switch Button - Moved to Bottom */}
                    <div className="mt-auto pt-6 border-t border-gray-100 w-full">
                        <button
                            type="button"
                            onClick={() => {
                                setIsPortalMode(!isPortalMode);
                                setLoginError('');
                                // Reset fields
                                setPortalUsername('');
                                setPortalPassword('');
                                setPortalType('admin'); // Default back to admin when switching
                            }}
                            className="w-full group flex items-center justify-between px-4 py-3 rounded-xl bg-gray-50 border border-gray-100 hover:border-luGreen/30 hover:bg-green-50/50 hover:shadow-md transition-all duration-300"
                        >
                            <div className="flex items-center gap-3">
                                <div className={`p-2 rounded-lg transition-colors duration-300 ${isPortalMode ? 'bg-amber-100 text-amber-600' : 'bg-gray-200 text-gray-500 group-hover:bg-luGreen group-hover:text-white'}`}>
                                    {isPortalMode ? <Users size={18} /> : <Lock size={18} />}
                                </div>
                                <div className="text-left">
                                    <p className="text-[10px] font-bold text-gray-400 uppercase tracking-wider leading-tight">
                                        {isPortalMode ? 'Switch Portal' : 'Restricted Access'}
                                    </p>
                                    <p className="text-xs font-bold text-gray-700 group-hover:text-luGreen transition-colors">
                                        {isPortalMode ? 'Back to User Login' : 'Admin & HR Portal'}
                                    </p>
                                </div>
                            </div>
                            <ArrowRight size={16} className="text-gray-300 group-hover:text-luGreen group-hover:translate-x-1 transition-all" />
                        </button>
                    </div>

                    <div className="mt-4 text-center md:hidden pb-2">
                        <p className="text-gray-500 text-sm">Don't have an account?</p>
                        <button onClick={toggleAuth} className="text-luGreen font-bold hover:underline mt-1 text-sm">
                            Sign Up Now
                        </button>
                    </div>
                </div>

                {/* Signup Form Section (Multi-step) */}
                <div className={`
                    w-full md:w-1/2 h-full flex flex-col justify-center px-8 sm:px-12 py-10 transition-all duration-700
                    md:absolute md:top-0 md:left-0
                    ${!isLogin 
                      ? 'flex opacity-100 z-10 md:translate-x-0' 
                      : 'hidden md:flex opacity-0 z-0 pointer-events-none md:translate-x-20'
                    }
                `}>

                    <div className="mb-4">
                        <h1 className="text-3xl font-bold text-gray-900 font-display">Create Account</h1>
                        <p className="text-gray-400 mt-2 text-sm flex items-center gap-2">
                            <span className="w-8 h-[1px] bg-luGold"></span> 
                            {signupStep === 'type-select' && 'Select your status'}
                            {signupStep === 'upload-proof' && 'Upload proof of status'}
                            {signupStep === 'review-data' && 'Review extracted data'}
                            {signupStep === 'upload-id' && 'Verify Identity & Register'}
                            {signupStep === 'manual-finder' && 'Alumni Record Finder'}
                        </p>
                    </div>

                    {signupError && (
                        <div className="mb-6 p-4 bg-red-50 text-red-800 text-sm rounded-xl flex items-start animate-fade-in border border-red-100 shadow-sm">
                            <XCircle size={18} className="mr-2 mt-0.5 flex-shrink-0 text-red-600" />
                            <span className="font-medium">{signupError}</span>
                        </div>
                    )}

                    {/* Status Message for Auto Process */}
                    {statusMessage && loading && (
                        <div className="mb-6 p-4 bg-blue-50 text-blue-800 text-sm rounded-xl flex items-center animate-pulse border border-blue-100 shadow-sm">
                            <Loader2 size={18} className="mr-2 animate-spin text-blue-600" />
                            <span className="font-bold">{statusMessage}</span>
                        </div>
                    )}

                    {/* Step 1: User Type Selection */}
                    {signupStep === 'type-select' && (
                        <div className="space-y-4 animate-fade-in">
                            <button 
                                onClick={() => handleUserTypeSelect('graduating')}
                                className="w-full p-5 rounded-2xl border-2 border-gray-100 hover:border-luGreen hover:bg-green-50/50 transition-all group flex items-center gap-4 text-left"
                            >
                                <div className="w-12 h-12 rounded-full bg-green-100 flex items-center justify-center text-luGreen group-hover:scale-110 transition-transform">
                                    <GraduationCap size={24} />
                                </div>
                                <div>
                                    <h3 className="font-bold text-gray-800">New Alumni</h3>
                                    <p className="text-xs text-gray-500 mt-1">Class of 2026 and above.</p>
                                </div>
                            </button>

                            <button 
                                onClick={() => handleUserTypeSelect('alumni')}
                                className="w-full p-5 rounded-2xl border-2 border-gray-100 hover:border-luGold hover:bg-amber-50/50 transition-all group flex items-center gap-4 text-left"
                            >
                                <div className="w-12 h-12 rounded-full bg-amber-100 flex items-center justify-center text-amber-600 group-hover:scale-110 transition-transform">
                                    <Users size={24} />
                                </div>
                                <div>
                                    <h3 className="font-bold text-gray-800">Old Alumni</h3>
                                    <p className="text-xs text-gray-500 mt-1">Class of 2025 and below.</p>
                                </div>
                            </button>
                        </div>
                    )}

                    {/* Step 2: Upload Proof */}
                    {signupStep === 'upload-proof' && (
                        <div className="animate-fade-in relative">
                            <div className="bg-white rounded-2xl p-1.5 shadow-sm border border-gray-100">
                                <FileUpload 
                                    onFileSelect={handleProofProcess} 
                                    isLoading={loading} 
                                    label={userType === 'graduating' ? "Upload Registration Form" : "Upload Diploma / Transcript"}
                                />
                            </div>

                             {/* Optional Manual Finder Link for Alumni */}
                             {userType === 'alumni' && (
                                <div className="mt-4 text-center">
                                    <button
                                        onClick={() => setSignupStep('manual-finder')}
                                        className="text-xs text-luGreen font-bold hover:underline hover:text-luGreen-dark transition-colors"
                                    >
                                        No longer have access to this document?
                                    </button>
                                </div>
                             )}

                             {/* Bottom Change Type Button */}
                             <div className="text-center mt-6">
                                <button 
                                    onClick={handleBackToTypeSelect}
                                    className="text-xs font-bold text-gray-400 hover:text-luGreen transition-colors flex items-center justify-center gap-2 mx-auto"
                                >
                                    <ArrowLeft size={14} /> Change Status Type
                                </button>
                            </div>
                        </div>
                    )}

                    {/* Manual Finder Step (Design Only) */}
                    {signupStep === 'manual-finder' && (
                        <div className="animate-fade-in space-y-5">
                            <div className="bg-amber-50 border border-amber-100 p-4 rounded-xl text-xs text-amber-800 leading-relaxed flex gap-3">
                                <Search size={20} className="shrink-0 mt-0.5"/>
                                <div>
                                    <p className="font-bold mb-1">Alumni Record Finder</p>
                                    Please provide your details exactly as they appeared in school records to locate your profile manually.
                                </div>
                            </div>

                            <div className="space-y-4">
                                <div className="grid grid-cols-2 gap-3">
                                    <div className="space-y-1">
                                        <label className="text-[10px] font-bold text-gray-500 uppercase tracking-wider ml-1">First Name</label>
                                        <input 
                                            type="text" 
                                            className="w-full px-4 py-3 rounded-xl bg-gray-50 border border-gray-200 focus:border-luGreen focus:bg-white focus:outline-none focus:ring-4 focus:ring-green-500/10 transition-all duration-300 text-gray-800 placeholder-gray-400 font-medium text-sm" 
                                            placeholder="e.g. Juan" 
                                        />
                                    </div>
                                    <div className="space-y-1">
                                        <label className="text-[10px] font-bold text-gray-500 uppercase tracking-wider ml-1">Last Name</label>
                                        <input 
                                            type="text" 
                                            className="w-full px-4 py-3 rounded-xl bg-gray-50 border border-gray-200 focus:border-luGreen focus:bg-white focus:outline-none focus:ring-4 focus:ring-green-500/10 transition-all duration-300 text-gray-800 placeholder-gray-400 font-medium text-sm" 
                                            placeholder="e.g. Dela Cruz" 
                                        />
                                    </div>
                                </div>

                                <div className="space-y-1">
                                    <label className="text-[10px] font-bold text-gray-500 uppercase tracking-wider ml-1">Program / Course</label>
                                    <input 
                                        type="text" 
                                        className="w-full px-4 py-3 rounded-xl bg-gray-50 border border-gray-200 focus:border-luGreen focus:bg-white focus:outline-none focus:ring-4 focus:ring-green-500/10 transition-all duration-300 text-gray-800 placeholder-gray-400 font-medium text-sm" 
                                        placeholder="e.g. BS Information Technology" 
                                    />
                                </div>

                                <div className="grid grid-cols-2 gap-3">
                                    <div className="space-y-1">
                                        <label className="text-[10px] font-bold text-gray-500 uppercase tracking-wider ml-1">Graduation Year</label>
                                        <input 
                                            type="text" 
                                            className="w-full px-4 py-3 rounded-xl bg-gray-50 border border-gray-200 focus:border-luGreen focus:bg-white focus:outline-none focus:ring-4 focus:ring-green-500/10 transition-all duration-300 text-gray-800 placeholder-gray-400 font-medium text-sm" 
                                            placeholder="e.g. 2023" 
                                        />
                                    </div>
                                    <div className="space-y-1">
                                        <label className="text-[10px] font-bold text-gray-500 uppercase tracking-wider ml-1">Birthdate</label>
                                        <input 
                                            type="date" 
                                            className="w-full px-4 py-3 rounded-xl bg-gray-50 border border-gray-200 focus:border-luGreen focus:bg-white focus:outline-none focus:ring-4 focus:ring-green-500/10 transition-all duration-300 text-gray-800 font-medium text-sm" 
                                        />
                                    </div>
                                </div>
                            </div>

                            <button className="w-full py-3 bg-luGreen text-white font-bold rounded-xl shadow-md hover:bg-luGreen-dark hover:shadow-lg transition-all transform active:scale-[0.98] mt-2">
                                Find Record
                            </button>

                            <button 
                                onClick={() => setSignupStep('upload-proof')} 
                                className="w-full py-2 text-xs font-bold text-gray-400 hover:text-luGreen transition-colors flex items-center justify-center gap-2"
                            >
                                <ArrowLeft size={14} /> Back to Upload
                            </button>
                        </div>
                    )}

                    {/* Step 3: Review Data */}
                    {signupStep === 'review-data' && extractedData && (
                        <div className="animate-fade-in space-y-4">
                            <div className="bg-gray-50/80 p-4 rounded-xl border border-gray-200 max-h-60 overflow-y-auto custom-scrollbar">
                                <div className="flex items-center justify-between mb-2">
                                    <span className="text-[10px] uppercase font-bold text-gray-500">Extracted Data (Editable)</span>
                                </div>
                                <div className="space-y-3">
                                    <div>
                                        <label className="text-[10px] text-luGreen font-bold block mb-1">Program / Course</label>
                                        <input 
                                            type="text" 
                                            value={formData.program || ''} 
                                            onChange={(e) => handleInputChange('program', e.target.value)}
                                            className="w-full bg-white border border-gray-200 rounded p-2 text-xs font-bold"
                                            placeholder="BSIT"
                                        />
                                    </div>
                                    <div className="grid grid-cols-2 gap-2">
                                        <div>
                                            <label className="text-[10px] text-luGreen font-bold block mb-1">
                                                {userType === 'graduating' ? 'Student Number' : 'S.O. Number'}
                                            </label>
                                            <input 
                                                type="text" 
                                                value={formData.student_number || ''} 
                                                onChange={(e) => handleInputChange('student_number', e.target.value)}
                                                className="w-full bg-white border border-gray-200 rounded p-2 text-xs font-bold"
                                            />
                                        </div>
                                         <div>
                                            <label className="text-[10px] text-luGreen font-bold block mb-1">Year / Batch</label>
                                            <input 
                                                type="text" 
                                                value={formData.year_level || ''} 
                                                onChange={(e) => handleInputChange('year_level', e.target.value)}
                                                className="w-full bg-white border border-gray-200 rounded p-2 text-xs font-bold"
                                                placeholder="2024"
                                            />
                                        </div>
                                    </div>
                                    <div className="grid grid-cols-2 gap-2">
                                        <div>
                                            <label className="text-[10px] text-luGreen font-bold block mb-1">First Name</label>
                                            <input 
                                                type="text" 
                                                value={formData.first_name || ''} 
                                                onChange={(e) => handleInputChange('first_name', e.target.value)}
                                                className="w-full bg-white border border-gray-200 rounded p-2 text-xs font-bold"
                                            />
                                        </div>
                                        <div>
                                            <label className="text-[10px] text-luGreen font-bold block mb-1">Last Name</label>
                                            <input 
                                                type="text" 
                                                value={formData.last_name || ''} 
                                                onChange={(e) => handleInputChange('last_name', e.target.value)}
                                                className="w-full bg-white border border-gray-200 rounded p-2 text-xs font-bold"
                                            />
                                        </div>
                                    </div>
                                    <div>
                                        <label className="text-[10px] text-luGreen font-bold block mb-1">Birthdate (Password)</label>
                                        <input 
                                            type="text" 
                                            value={formData.birthdate || ''} 
                                            onChange={(e) => handleInputChange('birthdate', e.target.value)}
                                            className={`w-full bg-white border rounded p-2 text-xs font-bold ${
                                                formData.birthdate && !isValidDateFormat(formData.birthdate) 
                                                ? 'border-red-500 text-red-600 bg-red-50' 
                                                : 'border-gray-200'
                                            }`}
                                            placeholder="MM-DD-YYYY"
                                        />
                                        {formData.birthdate && !isValidDateFormat(formData.birthdate) && (
                                            <p className="text-[10px] text-red-500 mt-1 font-bold">Must be MM-DD-YYYY</p>
                                        )}
                                    </div>
                                    <div>
                                        <label className="text-[10px] text-luGreen font-bold block mb-1">Email</label>
                                        <input 
                                            type="text" 
                                            value={formData.email || ''} 
                                            onChange={(e) => handleInputChange('email', e.target.value)}
                                            className="w-full bg-white border border-gray-200 rounded p-2 text-xs font-bold"
                                        />
                                    </div>
                                </div>
                            </div>
                            <div className="space-y-3 pt-2">
                                <button onClick={handleDataConfirmation} className="w-full py-3 bg-luGreen text-white rounded-xl text-xs font-bold shadow-md hover:bg-luGreen-dark transition-all transform active:scale-[0.98]">
                                    Next: Verify ID
                                </button>
                                <button 
                                    onClick={() => setSignupStep('upload-proof')}
                                    className="w-full py-2 text-xs font-bold text-gray-400 hover:text-luGreen transition-colors flex items-center justify-center gap-2"
                                >
                                    <ArrowLeft size={14} /> Re-upload Document
                                </button>
                            </div>
                        </div>
                    )}

                    {/* Step 4: Upload ID */}
                    {signupStep === 'upload-id' && (
                        <div className="animate-fade-in">
                            <div className="p-4 bg-amber-50 rounded-xl border border-amber-100 mb-4 text-xs text-amber-800">
                                <p className="font-bold mb-1">Identity Verification Required</p>
                                Please upload or take a photo of a valid Government or School ID to confirm that you are <strong>{formData.first_name} {formData.last_name}</strong>.
                                <br/><span className="mt-1 block text-[10px] opacity-80">Account will be created automatically upon successful verification.</span>
                            </div>
                            <div className="bg-white rounded-2xl p-1.5 shadow-sm border border-gray-100">
                                <FileUpload 
                                    onFileSelect={handleIdProcess} 
                                    isLoading={loading} 
                                    label="Upload Valid ID"
                                    acceptCamera={true}
                                />
                            </div>

                             <div className="text-center mt-6">
                                <button 
                                    onClick={() => setSignupStep('review-data')}
                                    className="text-xs font-bold text-gray-400 hover:text-luGreen transition-colors flex items-center justify-center gap-2 mx-auto"
                                >
                                    <ArrowLeft size={14} /> Back to Data Review
                                </button>
                            </div>
                        </div>
                    )}

                    <div className="mt-8 text-center md:hidden pb-4">
                        <button onClick={toggleAuth} className="text-luGreen font-bold hover:underline mt-1 text-sm">
                            Log In
                        </button>
                    </div>
                </div>

            </div>
          </div>
        </div>

      {/* Footer */}
      <footer className="w-full relative z-10 py-6 border-t border-white/40 bg-white/30 backdrop-blur-md text-gray-500 text-center text-sm mt-auto">
         <div className="container mx-auto px-4">
            <p className="font-medium text-gray-600">&copy; {new Date().getFullYear()} Laguna University</p>
         </div>
      </footer>
    </div>
  );
};

export default AuthPage;
